def judge(self, input: str, output: str, criteria: list, reference=None) -> dict:
    criteria_str = "\n".join(f"- {c}" for c in criteria)
    prompt = f"""Evaluate the response based on these criteria:\n{criteria_str}
Input: {input}\nResponse: {output}"""
    if reference:
        prompt += f"\nReference: {reference}"
    prompt += '\nReturn JSON: {"scores": {"criterion": {"score": 1-5, "explanation": "..."}}, "overall": N}'
    resp = self.client.chat.completions.create(
        model=self.model,
        messages=[{"role": "user", "content": prompt}],
        response_format={"type": "json_object"},
    )
    try:
        return json.loads(resp.choices[0].message.content)
    except json.JSONDecodeError:
        return {"error": "malformed JSON from judge", "scores": {}, "overall": None}
